import{_ as s,o as n,c as t,O as l}from"./chunks/framework.47655c42.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1775890403000}'),r={name:"guide/getting-started.md"};function i(p,a,c,e,d,_){return n(),t("div",null,a[0]||(a[0]=[l('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Quick Start</p><h1>快速开始</h1><div class="brand-hero__panel"><span class="brand-pill">Quick Overview</span><strong>ExecGov 不是单一聊天页面，而是一套已经有体验入口、交付路径和 CLI 桥接能力的执行平台。</strong><p>先从这里了解整体结构和入口选择。</p></div><p class="brand-lead"> 这份快速开始用于在最短路径内判断 <strong>当前可直接体验、接入和沟通的路线</strong>。 </p><div class="brand-chip-list"><span class="brand-chip">10 分钟看懂</span><span class="brand-chip">公开入口</span><span class="brand-chip">CLI 路线</span><span class="brand-chip">交付沟通</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../product/index.html">看产品概览</a><a class="cta-button" href="./faq.html">看常见问题</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // QUICK START</span><span>GUIDE 02</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">publicEntry</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;experience&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;login&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;register&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">productRoute</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;docs&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;delivery&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;deployment&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">localBridge</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;cli_login&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;register&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;run&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;agent&#39;</span><span class="matrix-panel__punct">]</span></span></div><div class="matrix-panel__callout">START WITH WHAT YOU CAN USE NOW</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">scope</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">public</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">state</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">live</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">goal</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">quick_start</span></span></div></div></div></section><section class="brand-grid brand-grid--four"><article class="brand-card"><p class="brand-kicker">01</p><h2>它不是普通聊天系统</h2><p>AI 在这里主要承担裁决入口和能力推荐角色，真实目标是让脚本与流程进入可控执行链路。</p></article><article class="brand-card"><p class="brand-kicker">02</p><h2>它已经有公开入口</h2><p>你现在可以直接使用体验页、登录页、注册页和文档站，不需要从演示入口跳转。</p></article><article class="brand-card"><p class="brand-kicker">03</p><h2>它已经有交付主线</h2><p>企业方向当前以“一个客户一个租户、一个客户一个网址”的交付模型为主线。</p></article><article class="brand-card"><p class="brand-kicker">04</p><h2>它已经有 CLI 桥接</h2><p><code>execgov-cli</code> 当前已经能覆盖登录、注册、列清单、执行和 Agent 骨架入口。</p></article></section><section class="brand-card"><p class="brand-kicker">Current Entry</p><h2>当前公开入口怎么理解</h2><table><thead><tr><th>入口</th><th>当前状态</th><th>适合谁</th><th>说明</th></tr></thead><tbody><tr><td><code>/experience</code></td><td>当前正式公开体验页</td><td>第一次体验的人</td><td>它是真实入口，不是只用于截图演示的占位页。</td></tr><tr><td><code>/login</code></td><td>当前正式登录页</td><td>已有账号的人</td><td>用于进入个人免费版或后续正式租户空间。</td></tr><tr><td><code>/register</code></td><td>当前正式注册页</td><td>还没有账号的人</td><td>注册成功当前由成功提示框承接，然后返回登录页，不是独立成功页。</td></tr><tr><td>产品文档</td><td>当前已成体系</td><td>产品、技术、售前</td><td>讲平台是什么、怎么交付、怎么部署、怎么演进。</td></tr><tr><td>CLI 文档</td><td>当前已成体系</td><td>开发者、本地接入场景</td><td>解释当前已实现和未实现的命令边界。</td></tr><tr><td>联系页</td><td>当前正式入口</td><td>要继续推进的人</td><td>用于试用、演示预约、交付沟通和合作咨询。</td></tr></tbody></table></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Try First</p><h2>体验路径</h2><ol class="brand-list"><li>先走公开体验路径，感受 AI 推荐与执行闭环</li><li>再看产品概览，判断这是不是你想要的平台类型</li><li>如果需要长期使用，再注册并登录</li><li>再判断是否需要进入 CLI 或团队 / 企业交付路径</li></ol></article><article class="brand-card"><p class="brand-kicker">Local Script</p><h2>本地脚本接入路径</h2><ol class="brand-list"><li>先看 <code>execgov-cli</code> 当前已经支持哪些命令</li><li>再准备你的脚本目录与 README</li><li>按当前规则理解 <code>register / list / run / agent</code> 的边界</li><li>如果涉及真实项目，再看混合执行和交付边界</li></ol></article><article class="brand-card"><p class="brand-kicker">Delivery</p><h2>团队 / 客户交付路径</h2><ol class="brand-list"><li>先看客户流程 / 交付，理解实际使用和热更新路径</li><li>再看部署方式，判断是否要单租户、平台治理或混合执行</li><li>确认适合你的版本与交付方式</li><li>最后通过联系页进入试用或演示沟通</li></ol></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Before You Start</p><h2>开始前先知道这些</h2><ul class="brand-list"><li>公开体验页适合先感受执行链路，不承接真实业务写入。</li><li>注册后会进入个人智能执行台，可以开始接入自己的第一个脚本。</li><li><code>execgov-cli</code> 当前已可用，本地接入能力会继续增强。</li><li>如果你本来就是团队或企业场景，直接走试用 / 演示沟通通常更高效。</li></ul></article><article class="brand-card"><p class="brand-kicker">Current Stage</p><h2>当前阶段覆盖哪些使用方式</h2><ul class="brand-list"><li>企业 <code>1.0</code> 交付主线已经成立。</li><li>个人免费入口已经成立。</li><li>CLI 最小桥梁能力已经成立。</li><li>标准团队协作能力和更丰富的套餐能力会继续扩展。</li></ul></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>完成入门判断后的常用入口</h2><p class="brand-lead">可按目标继续查看产品概览、客户交付、CLI 文档或常见问题，避免在所有页面之间反复切换。</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="../product/index.html"><span>Product</span><strong>产品概览</strong></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>客户流程 / 交付</strong></a><a class="brand-link-card" href="../product/cli.html"><span>CLI</span><strong>CLI 指引</strong></a><a class="brand-link-card" href="./faq.html"><span>FAQ</span><strong>常见问题</strong></a></div></div></section></div>',1)]))}const x=s(r,[["render",i]]);export{m as __pageData,x as default};
